145	/**
146	 * Small convenience for code that reads, mutates, and writes back under
147	 * the same serialization guarantee. The `update()` callback runs inside
148	 * the write chain, so concurrent update() calls on the same path are
149	 * serialized read-modify-write — no lost-update race.
150	 *
151	 * `initial` is used when the file does not exist or is malformed.
152	 */
153	export async function updateJson<T>(
154	  filePath: string,
155	  initial: () => T,
156	  update: (current: T) => T | Promise<T>,
157	): Promise<T> {
158	  const absPath = path.resolve(filePath);
159	  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
160	  let result: T;
161	  const next = prev.then(async () => {
162	    const current = await readJsonOrDefault<T>(absPath, initial);
163	    const updated = await update(current);
164	    result = updated;
165	    await mkdir(path.dirname(absPath), { recursive: true });
166	    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
167	    const body = JSON.stringify(updated, null, 2) + "\n";
168	    try {
169	      await writeFile(tmpPath, body, "utf8");
170	      await renameWithWindowsRetry(tmpPath, absPath);
171	    } catch (err) {
172	      await unlink(tmpPath).catch(() => {});
173	      throw err;
174	    }
175	  });
176	  writePendingByPath.set(
177	    absPath,
178	    next.catch((err) => {
179	      console.error(`[atomicJson] updateJson(${absPath}) failed:`, err);
180	    }),
181	  );
182	  await next;
183	  // Non-null assertion is safe: if `next` resolved, `result` was assigned.
184	  return result!;
185	}
