import { mkdir, readFile, rename, unlink, writeFile } from "node:fs/promises";
import path from "node:path";

/**
 * Windows-friendly rename: on NTFS, `rename()` can transiently fail with
 * EPERM/EBUSY when the target file is briefly held open by another
 * reader (antivirus, indexer, or even our own just-closed readFile on a
 * slow GC). POSIX fs do not exhibit this. Retry with exponential backoff
 * up to ~500ms, matching what git / electron-builder / pnpm do on
 * Windows.
 *
 * Non-Windows: single attempt, no retry needed.
 */
async function renameWithWindowsRetry(
  tmpPath: string,
  targetPath: string,
): Promise<void> {
  if (process.platform !== "win32") {
    await rename(tmpPath, targetPath);
    return;
  }
  const delays = [0, 10, 25, 50, 100, 150, 200]; // sum ≈ 535ms
  let lastErr: unknown;
  for (const d of delays) {
    if (d > 0) await new Promise((r) => setTimeout(r, d));
    try {
      await rename(tmpPath, targetPath);
      return;
    } catch (err: any) {
      if (err?.code !== "EPERM" && err?.code !== "EBUSY") throw err;
      lastErr = err;
    }
  }
  throw lastErr;
}

/**
 * Shared atomic JSON helper for bridge state files (.usage.json,
 * goal-state/*.json, and any future small per-state JSON).
 *
 * Design goals, aligned with how schedule-store.ts already behaves:
 *
 *   1. Corruption tolerance: ENOENT and malformed-JSON cases return a
 *      caller-supplied default instead of throwing. Bridge stays up.
 *   2. Concurrent-write safety: writes to the same path are serialized
 *      via a per-path `writePending` promise chain so overlapping
 *      write() calls never interleave bytes on disk.
 *   3. Crash-safe atomicity: writes go to "<path>.tmp-<pid>-<ts>" and
 *      are then `rename()`'d into place. On NTFS/ext4/APFS same-volume
 *      rename is atomic — readers see either the old content or the new,
 *      never a half-written file.
 *
 * Not a goal: cross-process locking. The bridge runs as a single
 * process; the serialization here handles in-process races. If two
 * bridges pointed at the same SKILL_DIR run simultaneously, last
 * writer wins — we do not protect against that.
 */

/** In-process serialization map: filePath → pending write chain. */
const writePendingByPath = new Map<string, Promise<void>>();

/**
 * Read a JSON file. ENOENT and parse errors return `fallback()` without
 * throwing — the caller decides what "empty" means (empty object,
 * default schema, etc.).
 *
 * Malformed-JSON case is logged (console.error) so silent data loss is
 * visible in the bridge log, but the call still succeeds.
 */
export async function readJsonOrDefault<T>(
  filePath: string,
  fallback: () => T,
): Promise<T> {
  let raw: string;
  try {
    raw = await readFile(filePath, "utf8");
  } catch (err: any) {
    if (err?.code === "ENOENT") return fallback();
    throw err;
  }
  if (raw.trim() === "") return fallback();
  try {
    return JSON.parse(raw) as T;
  } catch (err) {
    console.error(
      `[atomicJson] ${filePath} is not valid JSON; returning fallback. ` +
        `Error: ${(err as Error).message}`,
    );
    return fallback();
  }
}

/**
 * Atomically write `data` as pretty-printed JSON to `filePath`.
 *
 * Steps:
 *   1. Ensure parent dir exists (mkdir recursive).
 *   2. Write to "<filePath>.tmp-<pid>-<timestamp>".
 *   3. rename() the tmp file over the target. Same-volume rename is
 *      atomic on NTFS / POSIX fs.
 *
 * Concurrent calls for the same `filePath` are serialized via an
 * in-process promise chain so tmp files don't collide and we never
 * observe a torn write.
 *
 * Errors during step 2/3 are propagated; the caller decides whether to
 * retry or surface to the user. On step-3 failure we best-effort
 * unlink() the orphan tmp file so /tmp doesn't fill up over time.
 */
export async function atomicWriteJson(
  filePath: string,
  data: unknown,
): Promise<void> {
  const absPath = path.resolve(filePath);
  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
  const next = prev.then(async () => {
    await mkdir(path.dirname(absPath), { recursive: true });
    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
    const body = JSON.stringify(data, null, 2) + "\n";
    try {
      await writeFile(tmpPath, body, "utf8");
      await renameWithWindowsRetry(tmpPath, absPath);
    } catch (err) {
      // Best-effort cleanup; ignore failures since tmpPath may not exist.
      await unlink(tmpPath).catch(() => {});
      throw err;
    }
  });
  // Attach a catch so an earlier failure doesn't poison subsequent writes:
  // each caller awaits its own `next`, but the chain's `prev` for future
  // writers should resolve either way.
  const chained = next.catch((err) => {
    console.error(`[atomicJson] atomicWriteJson(${absPath}) failed:`, err);
  });
  writePendingByPath.set(absPath, chained);
  // Compare-and-delete：settle 後 map 內仍是本次的 chain 才移除——否則
  // 每個寫過的唯一路徑（goal-state/*.json、per-chat 檔）永久留一個
  // resolved promise entry，map 只增不減。
  chained.finally(() => {
    if (writePendingByPath.get(absPath) === chained) writePendingByPath.delete(absPath);
  });
  await next;
}

/**
 * Small convenience for code that reads, mutates, and writes back under
 * the same serialization guarantee. The `update()` callback runs inside
 * the write chain, so concurrent update() calls on the same path are
 * serialized read-modify-write — no lost-update race.
 *
 * `initial` is used when the file does not exist or is malformed.
 */
export async function updateJson<T>(
  filePath: string,
  initial: () => T,
  update: (current: T) => T | Promise<T>,
): Promise<T> {
  const absPath = path.resolve(filePath);
  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
  let result: T;
  const next = prev.then(async () => {
    const current = await readJsonOrDefault<T>(absPath, initial);
    const updated = await update(current);
    result = updated;
    await mkdir(path.dirname(absPath), { recursive: true });
    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
    const body = JSON.stringify(updated, null, 2) + "\n";
    try {
      await writeFile(tmpPath, body, "utf8");
      await renameWithWindowsRetry(tmpPath, absPath);
    } catch (err) {
      await unlink(tmpPath).catch(() => {});
      throw err;
    }
  });
  writePendingByPath.set(
    absPath,
    next.catch((err) => {
      console.error(`[atomicJson] updateJson(${absPath}) failed:`, err);
    }),
  );
  await next;
  // Non-null assertion is safe: if `next` resolved, `result` was assigned.
  return result!;
}

